INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Marina Acquisition DD Request List', 'Comprehensive marina DD request list', 'custom', 'Marina', '[]'::jsonb, true, true, 1, 'general_cre', true, '{"name": "Marina Acquisition DD Request List", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "financial", "title": "Financial", "items": [{"key": "marina_dd_001", "title": "COA", "requestText": "Chart of Accounts from marrina management software in Excel, QuickBooks or similar.", "priority": 1, "requestType": "document", "subCategory": "COA", "defaultOwnerRole": "seller"}, {"key": "marina_dd_002", "title": "Financial Statements", "requestText": "Balance sheets and monthly profit and loss statements for the trailing twelve months, and the prior 3 years ending 12/31.", "priority": 1, "requestType": "document", "subCategory": "Financial Statements", "defaultOwnerRole": "seller"}, {"key": "marina_dd_003", "title": "GLs", "requestText": "General ledger reports for current year, and prior 2-3 years, in Excel format.", "priority": 1, "requestType": "document", "subCategory": "GLs", "defaultOwnerRole": "seller"}, {"key": "marina_dd_004", "title": "Payroll", "requestText": "Payroll register for last two pay periods.", "priority": 1, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_005", "title": "Payroll", "requestText": "When was your last rate increase, by how much did you increase, and how often do you raise rates (history for last 3 years)?", "priority": 1, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_006", "title": "REIT", "requestText": "Please complete tab 8.", "priority": 1, "requestType": "document", "subCategory": "REIT", "defaultOwnerRole": "seller"}, {"key": "marina_dd_007", "title": "Rent Rolls", "requestText": "Trailing twelve months and last 2-3 year-end rent rolls, broken out by month, for boat storage and commercial tenants.", "priority": 1, "requestType": "document", "subCategory": "Rent Rolls", "defaultOwnerRole": "seller"}, {"key": "marina_dd_008", "title": "Trial Balances", "requestText": "Trial Balance for last 2-3 years in excel, QuickBooks or similar.", "priority": 1, "requestType": "document", "subCategory": "Trial Balances", "defaultOwnerRole": "seller"}, {"key": "marina_dd_009", "title": "Accounts Receivable", "requestText": "Accounts receivable aging and delinquency reports and accounts payable aging reports for the twelve(12) months immediately preceding the effective date", "priority": 2, "requestType": "document", "subCategory": "Accounts Receivable", "defaultOwnerRole": "seller"}, {"key": "marina_dd_010", "title": "Bank", "requestText": "Copies of the monthly bank statements, Bank Records, cash receipts journals, and bank reconciliation for the twenty-four (24) months immediately preceding the effective date", "priority": 2, "requestType": "document", "subCategory": "Bank", "defaultOwnerRole": "seller"}, {"key": "marina_dd_011", "title": "CapEx Budget", "requestText": "The monthly capital expenditure budget for the twenty-four (24) months immediately preceding the effective date", "priority": 2, "requestType": "document", "subCategory": "CapEx Budget", "defaultOwnerRole": "seller"}, {"key": "marina_dd_012", "title": "CapEx Spend", "requestText": "Have there been any big Capital projects in the last two years and what are costs associated with these projects? Example new 100K spent on installing new docks, new RV sites, buildings etc....", "priority": 2, "requestType": "document", "subCategory": "CapEx Spend", "defaultOwnerRole": "seller"}, {"key": "marina_dd_013", "title": "Income Tax-Federal", "requestText": "Asset & Depreciation Report", "priority": 2, "requestType": "document", "subCategory": "Income Tax-Federal", "defaultOwnerRole": "seller"}, {"key": "marina_dd_014", "title": "Income Tax-Federal", "requestText": "Sellers'' filed income tax returns relating to each property for the current and prior two (2) tax years, or, if the applicable property has been owned by a seller for less than two (2) tax years, for the period of ownership", "priority": 2, "requestType": "document", "subCategory": "Income Tax-Federal", "defaultOwnerRole": "seller"}, {"key": "marina_dd_015", "title": "Income Tax-State", "requestText": "Sellers'' filed state sales tax returns relating to each property for the current and prior two (2) tax years, or, if the applicable property has been owned by a seller for less than two (2) tax years, for the period of ownership", "priority": 2, "requestType": "document", "subCategory": "Income Tax-State", "defaultOwnerRole": "seller"}, {"key": "marina_dd_016", "title": "Inventory", "requestText": "Inventory on hand for ship store, service department, parts, restaurant, fuel, etc.", "priority": 2, "requestType": "document", "subCategory": "Inventory", "defaultOwnerRole": "seller"}, {"key": "marina_dd_017", "title": "Pedestal", "requestText": "Please populate Pedestal tab if applicable", "priority": 2, "requestType": "document", "subCategory": "Pedestal", "defaultOwnerRole": "seller"}, {"key": "marina_dd_018", "title": "Personal Property", "requestText": "Please complete tab 7.", "priority": 2, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}, {"key": "marina_dd_019", "title": "Personal Property", "requestText": "Sellers'' personal property tax bills and renditions relating to each property for the current and prior two (2) tax years or, if the applicable property has been owned by a seller for less than two (2) tax years, for the period of ownership", "priority": 2, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}, {"key": "marina_dd_020", "title": "Property Tax", "requestText": "Property''s real estate tax bills and assessments for the current and prior two (2) tax years or, if the applicable property has been owned by a seller for less than two (2) tax years, for the period of ownership", "priority": 2, "requestType": "document", "subCategory": "Property Tax", "defaultOwnerRole": "seller"}, {"key": "marina_dd_021", "title": "Security Deposits", "requestText": "Security Deposit Policy - what are the policies (e.g. one month rent) & fare discounts given to customers", "priority": 2, "requestType": "document", "subCategory": "Security Deposits", "defaultOwnerRole": "seller"}, {"key": "marina_dd_022", "title": "Utilities", "requestText": "Please complete tab 6.", "priority": 2, "requestType": "document", "subCategory": "Utilities", "defaultOwnerRole": "seller"}, {"key": "marina_dd_023", "title": "Utilities", "requestText": "Utility bills for the twelve (12) months immediately preceding the effective date. (e.g.. electric, water, sewer, gas, trash, waste, phone, cable, internet, etc.)", "priority": 2, "requestType": "document", "subCategory": "Utilities", "defaultOwnerRole": "seller"}, {"key": "marina_dd_024", "title": "Banking", "requestText": "List of Recurring Charges & Automatic Debits", "priority": 3, "requestType": "document", "subCategory": "Banking", "defaultOwnerRole": "seller"}, {"key": "marina_dd_025", "title": "Check Registers", "requestText": "Check Registers for the prior twelve months", "priority": 3, "requestType": "document", "subCategory": "Check Registers", "defaultOwnerRole": "seller"}, {"key": "marina_dd_026", "title": "Credit Cards", "requestText": "List of credit card holders at each property & credit limit for each card holder", "priority": 3, "requestType": "document", "subCategory": "Credit Cards", "defaultOwnerRole": "seller"}, {"key": "marina_dd_027", "title": "Customer ACH info", "requestText": "List of customers paying by direct debit, and subsequent bank account information", "priority": 3, "requestType": "document", "subCategory": "Customer ACH info", "defaultOwnerRole": "seller"}, {"key": "marina_dd_028", "title": "Payments", "requestText": "Please list all accepted payment types (i.e. cash, credit card, check, ACH)", "priority": 3, "requestType": "document", "subCategory": "Payments", "defaultOwnerRole": "seller"}, {"key": "marina_dd_029", "title": "Security Deposits", "requestText": "A schedule/summary of customers with security deposits on file and third party tenants", "priority": 3, "requestType": "document", "subCategory": "Security Deposits", "defaultOwnerRole": "seller"}, {"key": "supp_leases", "title": "Lease Summary", "requestText": "Please complete the Summary of Leases tab for all third-party tenants and lease obligations including term, rent amount, security deposits, annual increases, renewal options, and tenant responsibilities. This includes both income-producing leases (office space, boat club, restaurant) and expense leases (submerged land lease, equipment leases).", "priority": 1, "requestType": "document", "subCategory": "Leases", "defaultOwnerRole": "seller"}, {"key": "supp_utilities", "title": "Utility Summary", "requestText": "Please complete the Utility Summary tab listing all property utilities including provider name, service type, account number, and contact information for account transfers.", "priority": 2, "requestType": "document", "subCategory": "Utilities", "defaultOwnerRole": "seller"}]}, {"key": "hr_and_payroll", "title": "HR & Payroll", "items": [{"key": "marina_dd_030", "title": "Org Chart", "requestText": "Property org chart.", "priority": 1, "requestType": "document", "subCategory": "Org Chart", "defaultOwnerRole": "seller"}, {"key": "marina_dd_031", "title": "Payroll", "requestText": "Employee roster: Please include names, titles, departments, special skills, pay rates, job descriptions, length of employment, approximate number of hours worked per week, number of weeks worked per year, amount of paid time off and vacation time provided, and the remaining paid time off and vacation day balance for each employee for the current year.", "priority": 1, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_032", "title": "Payroll", "requestText": "Payroll payment schedule (i.e. weekly, bi-weekly, monthly)", "priority": 1, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_033", "title": "Benefits", "requestText": "Current employee benefits (e.g.. health, dental, vision, supplemental, 401k) and carrier for each benefit plan along with list of premiums paid by employer and employee", "priority": 2, "requestType": "document", "subCategory": "Benefits", "defaultOwnerRole": "seller"}, {"key": "marina_dd_034", "title": "Bonus", "requestText": "Detailed list of bonuses offered & historical records from past 2 years", "priority": 3, "requestType": "document", "subCategory": "Bonus", "defaultOwnerRole": "seller"}, {"key": "marina_dd_035", "title": "Cobra", "requestText": "TPA (third party administrators) agreements for COBRA benefit administration and/ or worker''s comp claims", "priority": 3, "requestType": "document", "subCategory": "Cobra", "defaultOwnerRole": "seller"}, {"key": "marina_dd_036", "title": "Employment Agreements", "requestText": "Employment agreements, contracts, consulting agreements, non-compete agreements.", "priority": 3, "requestType": "document", "subCategory": "Employment Agreements", "defaultOwnerRole": "seller"}, {"key": "marina_dd_037", "title": "Handbook", "requestText": "Employee handbook, if applicable", "priority": 3, "requestType": "document", "subCategory": "Handbook", "defaultOwnerRole": "seller"}, {"key": "marina_dd_038", "title": "Medical Claims", "requestText": "List last two years of medical claims data", "priority": 3, "requestType": "document", "subCategory": "Medical Claims", "defaultOwnerRole": "seller"}, {"key": "marina_dd_039", "title": "OSHA", "requestText": "OSHA 300 Reports 300, 300A and 301 for past 3 years.", "priority": 3, "requestType": "document", "subCategory": "OSHA", "defaultOwnerRole": "seller"}, {"key": "marina_dd_040", "title": "Payroll", "requestText": "List of individuals working and not compensated through payroll", "priority": 3, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_041", "title": "Whistleblower", "requestText": "List any whistleblower or wrongful termination matters.", "priority": 3, "requestType": "document", "subCategory": "Whistleblower", "defaultOwnerRole": "seller"}]}, {"key": "legal", "title": "Legal", "items": [{"key": "marina_dd_042", "title": "HOA Documents", "requestText": "HOA/POA documents, if applicable.", "priority": 1, "requestType": "document", "subCategory": "HOA Documents", "defaultOwnerRole": "seller"}, {"key": "marina_dd_043", "title": "HOA Requirements", "requestText": "Written explanation of the monthly/annual responsibilities/requirements to the HOA/POA, if applicable", "priority": 1, "requestType": "document", "subCategory": "HOA Requirements", "defaultOwnerRole": "seller"}, {"key": "marina_dd_044", "title": "Boat/Vehicle Titles", "requestText": "Marina-owned boat & vehicle titles", "priority": 2, "requestType": "document", "subCategory": "Boat/Vehicle Titles", "defaultOwnerRole": "seller"}, {"key": "marina_dd_045", "title": "Title", "requestText": "Title to property", "priority": 2, "requestType": "document", "subCategory": "Title", "defaultOwnerRole": "seller"}, {"key": "supp_permits", "title": "Permits & Licenses Summary", "requestText": "Please complete the Summary of Permits tab listing all permits and licenses including type, purpose, term, expiry date, and department contact information.", "priority": 1, "requestType": "document", "subCategory": "Permits", "defaultOwnerRole": "seller"}]}, {"key": "operations", "title": "Operations", "items": [{"key": "marina_dd_046", "title": "Rate Card", "requestText": "Current rate card, as well as historical rates over the last 3-5 years.", "priority": 1, "requestType": "document", "subCategory": "Rate Card", "defaultOwnerRole": "seller"}, {"key": "marina_dd_047", "title": "Dredging", "requestText": "Please summarize the history of dredging at the property, as well as how often you dredge, and what that work typically costs.", "priority": 1, "requestType": "document", "subCategory": "Dredging", "defaultOwnerRole": "seller"}, {"key": "marina_dd_048", "title": "Do you allow customers to rent theirs boats or RVs through A", "requestText": "Do you allow customers to rent theirs boats or RVs through Airbnb/VBRO, or other third-party?", "priority": 1, "requestType": "document", "subCategory": null, "defaultOwnerRole": "seller"}, {"key": "marina_dd_049", "title": "Leases", "requestText": "Template boat storage, RV park, and other rental contracts (e.g. boat rentals, cabin rentals, etc.)", "priority": 2, "requestType": "document", "subCategory": "Leases", "defaultOwnerRole": "seller"}, {"key": "marina_dd_050", "title": "Leases", "requestText": "Please provide PDF Copies of all leases in-place with vendors, as well as upland and/or submerged land leases. Additionally, please summarize on tab 3 all the applicable leases for the property. These can include leases with tenants that pay the property, as well as leases where property pays as a lessee (e.g. submerged land or ground lease, equipment lease). Please include name of the vendor, monthly rent, lease term and expiry date.", "priority": 2, "requestType": "document", "subCategory": "Leases", "defaultOwnerRole": "seller"}, {"key": "marina_dd_051", "title": "Permits/Licenses", "requestText": "Please provide copies of all business licenses, sales and use tax licenses, liquor license, retail license, UST/AST permit, storm water permit, hazardous material permit, and any other operating permits and licenses required for operation", "priority": 2, "requestType": "document", "subCategory": "Permits/Licenses", "defaultOwnerRole": "seller"}, {"key": "marina_dd_052", "title": "Permits/Licenses", "requestText": "Pleas complete tab 4.", "priority": 2, "requestType": "document", "subCategory": "Permits/Licenses", "defaultOwnerRole": "seller"}, {"key": "marina_dd_053", "title": "Registered Vehicles/Vessels Etc.", "requestText": "Please complete tab 5.", "priority": 2, "requestType": "document", "subCategory": "Registered Vehicles/Vessels Etc.", "defaultOwnerRole": "seller"}, {"key": "marina_dd_054", "title": "Service Contracts", "requestText": "PDF Copies of all service agreements/contracts currently in-place, as well as completion of tab 2.", "priority": 2, "requestType": "document", "subCategory": "Service Contracts", "defaultOwnerRole": "seller"}, {"key": "marina_dd_055", "title": "Leases", "requestText": "Please provide copies of customer contracts (boat storage, RV park, long-term rentals, etc.)", "priority": 2, "requestType": "document", "subCategory": "Leases", "defaultOwnerRole": "seller"}, {"key": "marina_dd_056", "title": "Permits/Licenses", "requestText": "Any additional agreements in-place, including marina operating permits, easements, licenses, etc.", "priority": 2, "requestType": "document", "subCategory": "Permits/Licenses", "defaultOwnerRole": "seller"}, {"key": "marina_dd_057", "title": "Electric/Utilities", "requestText": "Please explain the customer billing procedure (and include whether utilities are included).", "priority": 3, "requestType": "document", "subCategory": "Electric/Utilities", "defaultOwnerRole": "seller"}, {"key": "marina_dd_058", "title": "Increases", "requestText": "Please explain your rent increase notice procedure and schedule (i.e. do rates increase on a particular date each year, how do you determine the %/$ increase, etc.)", "priority": 3, "requestType": "document", "subCategory": "Increases", "defaultOwnerRole": "seller"}, {"key": "marina_dd_059", "title": "Late Fees", "requestText": "Is there a late fees policy?", "priority": 3, "requestType": "document", "subCategory": "Late Fees", "defaultOwnerRole": "seller"}, {"key": "marina_dd_060", "title": "Memberships/Discounts", "requestText": "Details of membership programs and discounts offered and any documents that support this where applicable (i.e. if not in the Storage / Slip Agreement)", "priority": 3, "requestType": "document", "subCategory": "Memberships/Discounts", "defaultOwnerRole": "seller"}, {"key": "marina_dd_061", "title": "Wait List", "requestText": "Waiting lists for storage and slip and hurricane storage, if applicable", "priority": 3, "requestType": "document", "subCategory": "Wait List", "defaultOwnerRole": "seller"}, {"key": "supp_service_agreements", "title": "Service Agreements Summary", "requestText": "Please complete the Service Agreements tab listing all vendor contracts including terms, fees, expiry dates, and termination notice requirements.", "priority": 1, "requestType": "document", "subCategory": "Service Agreements", "defaultOwnerRole": "seller"}, {"key": "supp_boats_vehicles", "title": "Marina-Owned Vehicles & Equipment", "requestText": "Please complete the Boats & Vehicle Info tab listing all marina-owned vehicles and equipment including type, model, serial number, registration, use, year, engine details, purchase date, and condition.", "priority": 1, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}, {"key": "supp_personal_property", "title": "Personal Property Inventory", "requestText": "Please complete the Personal Property Template tab listing all personal property items including description, age, location, and current market value.", "priority": 2, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}, {"key": "supp_pedestal", "title": "Pedestal Information", "requestText": "Please complete the Pedestal Information tab listing pedestal count, model numbers, power type, and photos.", "priority": 2, "requestType": "document", "subCategory": "Pedestals", "defaultOwnerRole": "seller"}]}, {"key": "real_estate", "title": "Real Estate", "items": [{"key": "marina_dd_062", "title": "Appraisals", "requestText": "Past appraisal(s) of the property", "priority": 1, "requestType": "document", "subCategory": "Appraisals", "defaultOwnerRole": "seller"}, {"key": "marina_dd_063", "title": "Environmental", "requestText": "Previous environmental Phase I and/or Phase II, if available", "priority": 1, "requestType": "document", "subCategory": "Environmental", "defaultOwnerRole": "seller"}, {"key": "marina_dd_064", "title": "Property Condition", "requestText": "Past property condition reports, if available", "priority": 1, "requestType": "document", "subCategory": "Property Condition", "defaultOwnerRole": "seller"}, {"key": "marina_dd_065", "title": "Real Property", "requestText": "Please provide confirmation of parcels or legal descriptions to show what parcels of land are included in the sale", "priority": 1, "requestType": "document", "subCategory": "Real Property", "defaultOwnerRole": "seller"}, {"key": "marina_dd_066", "title": "Site Plan", "requestText": "Marina site plan and dock layout for each of the properties", "priority": 1, "requestType": "document", "subCategory": "Site Plan", "defaultOwnerRole": "seller"}, {"key": "marina_dd_067", "title": "Surveys", "requestText": "Surveys of the properties (e.g. ALTA, bathymetric, etc.)", "priority": 1, "requestType": "document", "subCategory": "Surveys", "defaultOwnerRole": "seller"}, {"key": "marina_dd_068", "title": "Water Rights", "requestText": "Documents establishing water rights.", "priority": 1, "requestType": "document", "subCategory": "Water Rights", "defaultOwnerRole": "seller"}, {"key": "marina_dd_069", "title": "Zoning", "requestText": "Zoning Letter from local municipality or any documentation showing property zoning.", "priority": 1, "requestType": "document", "subCategory": "Zoning", "defaultOwnerRole": "seller"}, {"key": "marina_dd_070", "title": "Insurance", "requestText": "Elevation Certificates (required by Flood insurance)", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_071", "title": "Real Estate", "requestText": "All master plans for the properties, if available", "priority": 2, "requestType": "document", "subCategory": "Real Estate", "defaultOwnerRole": "seller"}, {"key": "supp_boats_vehicles", "title": "Marina-Owned Vehicles & Equipment", "requestText": "Please complete the Boats & Vehicle Info tab listing all marina-owned vehicles and equipment including type, model, serial number, registration, use, year, engine details, purchase date, and condition.", "priority": 1, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}]}, {"key": "information_technology", "title": "Information Technology", "items": [{"key": "marina_dd_072", "title": "IT", "requestText": "Please complete tab 10", "priority": 2, "requestType": "document", "subCategory": "IT", "defaultOwnerRole": "seller"}]}, {"key": "inspections", "title": "Inspections", "items": [{"key": "marina_dd_073", "title": "Inspections", "requestText": "Certificates of occupancy and zoning reports", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_074", "title": "Inspections", "requestText": "Fire Inspection / Equipment testing", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_075", "title": "Inspections", "requestText": "Recent Electrical Inspection", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_076", "title": "Inspections", "requestText": "Recent Forklift Inspection", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_077", "title": "Inspections", "requestText": "Underground Storage Tank Inspection", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_078", "title": "Inspections", "requestText": "Weights and Measures Inspection (Fuel Pumps), if available", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}]}, {"key": "insurance", "title": "Insurance", "items": [{"key": "marina_dd_079", "title": "Insurance", "requestText": "A detailed description of any outstanding workers'' compensation claims relating to the properties for the twenty-four (24) months immediately preceding the effective date.", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_080", "title": "Insurance", "requestText": "Flood insurance policies", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_081", "title": "Insurance", "requestText": "Insurance loss run for preceding 5 years", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_082", "title": "Insurance", "requestText": "Insurance policies", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_083", "title": "Insurance", "requestText": "Pending or threatened claims for the preceding 36 months", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_084", "title": "Insurance", "requestText": "Storage tank insurance", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_085", "title": "Insurance", "requestText": "Title insurance", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_086", "title": "Insurance", "requestText": "Copy of workers'' comp policy", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_087", "title": "Customer Proof Of Insurance", "requestText": "Does the Marina ask their customers to name the marina as additionally insured on their vessels insurance?", "priority": 2, "requestType": "document", "subCategory": "Customer Proof Of Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_088", "title": "Customer Proof Of Insurance", "requestText": "Does the marina request copies of boat storage customer insurance?", "priority": 2, "requestType": "document", "subCategory": "Customer Proof Of Insurance", "defaultOwnerRole": "seller"}]}, {"key": "marketing", "title": "Marketing", "items": [{"key": "marina_dd_089", "title": "Advertising", "requestText": "Marketing plans, advertising agreements, brochures, welcome packages. Any commitments to boat shows, radio, newspaper, magazines, social media etc.", "priority": 3, "requestType": "document", "subCategory": "Advertising", "defaultOwnerRole": "seller"}, {"key": "marina_dd_090", "title": "Email Customer List", "requestText": "Customer lists with emails", "priority": 3, "requestType": "document", "subCategory": "Email Customer List", "defaultOwnerRole": "seller"}, {"key": "marina_dd_091", "title": "Marketing", "requestText": "Marina''s logo and high res photo''s.", "priority": 3, "requestType": "document", "subCategory": "Marketing", "defaultOwnerRole": "seller"}]}, {"key": "vendors", "title": "Vendors", "items": [{"key": "marina_dd_092", "title": "AP Vendors", "requestText": "List of vendors that work with the property (i.e. pest, fuel, security, landscaping, cleaning, machinery, ice, uniform, fire inspections, maintenance, etc.)", "priority": 3, "requestType": "document", "subCategory": "AP Vendors", "defaultOwnerRole": "seller"}, {"key": "marina_dd_093", "title": "W9''s", "requestText": "Copies of W9 and Tax ID for each vendor", "priority": 3, "requestType": "document", "subCategory": "W9''s", "defaultOwnerRole": "seller"}]}, {"key": "reit_compliance", "title": "REIT Compliance", "items": [{"key": "reit_001", "title": "Do you expect the value of personal property (e.g., furniture, equipment, applia", "requestText": "Do you expect the value of personal property (e.g., furniture, equipment, appliances, light fixtures) of the Property being acquired, including expected future additions, to represent 15% or more of the total purchase price of the Property?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_002", "title": "If yes, is any of this personal property leased to tenants in connection with th", "requestText": "If yes, is any of this personal property leased to tenants in connection with the leased Property?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_003", "title": "If yes, what is the fair market value of such personal property?", "requestText": "If yes, what is the fair market value of such personal property?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_004", "title": "What''s the minimum rental period for a standard lease?", "requestText": "What''s the minimum rental period for a standard lease?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_005", "title": "Do any leases provide for rent based in whole or in part on the net income or ne", "requestText": "Do any leases provide for rent based in whole or in part on the net income or net profits of the tenant?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_006", "title": "Do any leases that provide for rent based in whole or in part on a fixed percent", "requestText": "Do any leases that provide for rent based in whole or in part on a fixed percentage of gross receipts or sales also provide for a reduction of such gross receipts or sales by the amount of any tenant expense in a manner that results in rent in substance being based on net income or profits?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_007", "title": "Are there any leases with tenants that permit subleasing, where the terms of the", "requestText": "Are there any leases with tenants that permit subleasing, where the terms of the lease or sublease provide for rent based on terms similar to the terms above?  (These terms of the sublease can taint the terms of the lease.)", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_008", "title": "If yes, are there any subleases currently in place?  If yes, please list subleas", "requestText": "If yes, are there any subleases currently in place?  If yes, please list subleases:", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_009", "title": "Does the property or its investors own directly or indirectly a 10% interest in ", "requestText": "Does the property or its investors own directly or indirectly a 10% interest in any tenant?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_010", "title": "Is the property reimbursed by tenants for any items other than the following: (a", "requestText": "Is the property reimbursed by tenants for any items other than the following: (a) real estate taxes; (b) insurance premiums; (c) maintenance charges; (d) utilities; (e) expense of an independent audit of the tenant\u2019s books to determine the tenant\u2019s gross sales (on which to base percentage rent); (f) attorney fees incurred as a result of a default on the lease; (g) expenses for marketing the Property; or (h) similar items?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_011", "title": "In addition to rent and the reimbursements listed above, do any leases require t", "requestText": "In addition to rent and the reimbursements listed above, do any leases require the tenant to pay any additional amounts other than the following: (a) rent increases based upon an objective cost-of-living index; (b) late payment charges; (c) forfeited security deposits; or (d) lease termination payments?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_012", "title": "Did the books and records, including budgets, of the seller indicate the owner r", "requestText": "Did the books and records, including budgets, of the seller indicate the owner receives any amounts other than rent, reimbursements and escalations?  For example, is there an amount listed as \u201cOther Income\u201d?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_013", "title": "If yes, what is the nature of the other income?  Please list all sources.", "requestText": "If yes, what is the nature of the other income?  Please list all sources.", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_014", "title": "What is the anticipated useful life of the floating docks?", "requestText": "What is the anticipated useful life of the floating docks?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_015", "title": "Is the method used to affix the docks designed and built with a configuration in", "requestText": "Is the method used to affix the docks designed and built with a configuration in mind which is not intended to be moved or destroyed?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_016", "title": "Is the method used affixed to the seabed meant to be permanent (i.e., not easily", "requestText": "Is the method used affixed to the seabed meant to be permanent (i.e., not easily destroyed)?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_017", "title": "Is the method used meant to be resistant to inclement weather (e.g., hurricanes)", "requestText": "Is the method used meant to be resistant to inclement weather (e.g., hurricanes)?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_018", "title": "If the method used needed to be reconfigured or moved, would this cause the pili", "requestText": "If the method used needed to be reconfigured or moved, would this cause the pilings and/or the floating dock to be damaged or destroyed?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_019", "title": "How long would it take to remove the method used from the seabed?", "requestText": "How long would it take to remove the method used from the seabed?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_020", "title": "Is it monetarily prohibitive to make changes, alter, or move the method used to ", "requestText": "Is it monetarily prohibitive to make changes, alter, or move the method used to connect the floating docks to the sea bottom?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_021", "title": "If the marina ceased to operate, does the local municipality require removal or ", "requestText": "If the marina ceased to operate, does the local municipality require removal or destruction of the method used?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_022", "title": "Are there any other circumstances that would indicate or suggest the expected pe", "requestText": "Are there any other circumstances that would indicate or suggest the expected period of affixation to the seabed is not indefinite?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}]}, {"key": "it_infrastructure", "title": "IT Infrastructure", "items": [{"key": "it_001", "title": "Is the IT Equipment Part of the Sale (Yes/No)? (I.e. PCs and Related Equipment, ", "requestText": "Is the IT Equipment Part of the Sale (Yes/No)? (I.e. PCs and Related Equipment, Copiers, Scanners)", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_002", "title": "Describe Your Internet Service Type (i.e. Cable, DSL, Fiber, T1, Satellite/Cellu", "requestText": "Describe Your Internet Service Type (i.e. Cable, DSL, Fiber, T1, Satellite/Cellular)?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_003", "title": "What is the Speed of Your Internet Service?", "requestText": "What is the Speed of Your Internet Service?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_004", "title": "Is your IP Addressing Automatic or Static?", "requestText": "Is your IP Addressing Automatic or Static? If Static, please provide details: IP address, Subnet Mask, Gateway Address, DNS1, and DNS2", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_005", "title": "Who is your Internet Service Provider and their contact information?", "requestText": "Who is your Internet Service Provider and their contact information?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_006", "title": "Who is Authorized to Make Changes on your Office Internet Account?", "requestText": "Who is Authorized to Make Changes on your Office Internet Account?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_007", "title": "Please fill out the information below: (If all your computers are housed inside ", "requestText": "Please fill out the information below: (If all your computers are housed inside 1 building, the fill out the information for Building 1)", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_008", "title": "Do You Provide WiFi Service to Residents/Guests?", "requestText": "Do You Provide WiFi Service to Residents/Guests? If Yes, is the service in the form of Hotspot(s) or Park-wide? Who manages the service?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_009", "title": "Do You Provide Walk-Up Computer Access to Residents/Guests?", "requestText": "Do You Provide Walk-Up Computer Access to Residents/Guests?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_010", "title": "Is there a Firewall connected to your Office Internet Service (Yes/No)?", "requestText": "Is there a Firewall connected to your Office Internet Service (Yes/No)?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_011", "title": "Are there any Servers Connected to the Network?", "requestText": "Are there any Servers Connected to the Network? If Yes, please include details: Function, Make and Model Number, Serial Number.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_012", "title": "Are Your Computers Connected to the Network via a Cable or are they Wireless?", "requestText": "Are Your Computers Connected to the Network via a Cable or are they Wireless?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_013", "title": "Are There any E-mail Addresses that need to be transferred or Redirected? If yes", "requestText": "Are There any E-mail Addresses that need to be transferred or Redirected? If yes, please list all users email addresses below.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_014", "title": "Does Your Property Have a Website (Yes/No)?", "requestText": "Does Your Property Have a Website (Yes/No)? IMPORTANT: please provide Site Address, Site Administrator Name, Hosting Company and Contact Info, and the Email Address listed at the Registrar.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_015", "title": "Do you have any Leased Equipment (i.e Copier, Stamp Machine)? If yes, please pro", "requestText": "Do you have any Leased Equipment (i.e Copier, Stamp Machine)? If yes, please provide the companies name and contact information.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_016", "title": "What property Management Software do you use and can you provide us with their c", "requestText": "What property Management Software do you use and can you provide us with their contact information?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_017", "title": "Is Your Property Management Software Hosted? If yes, please provide contact info", "requestText": "Is Your Property Management Software Hosted? If yes, please provide contact information for hosting service or sales contact.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Financial DD Requests', 'Financial - 31 items', 'custom', 'Marina', '[]'::jsonb, true, true, 2, 'general_cre', true, '{"name": "Financial", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "financial", "title": "Financial", "items": [{"key": "marina_dd_001", "title": "COA", "requestText": "Chart of Accounts from marrina management software in Excel, QuickBooks or similar.", "priority": 1, "requestType": "document", "subCategory": "COA", "defaultOwnerRole": "seller"}, {"key": "marina_dd_002", "title": "Financial Statements", "requestText": "Balance sheets and monthly profit and loss statements for the trailing twelve months, and the prior 3 years ending 12/31.", "priority": 1, "requestType": "document", "subCategory": "Financial Statements", "defaultOwnerRole": "seller"}, {"key": "marina_dd_003", "title": "GLs", "requestText": "General ledger reports for current year, and prior 2-3 years, in Excel format.", "priority": 1, "requestType": "document", "subCategory": "GLs", "defaultOwnerRole": "seller"}, {"key": "marina_dd_004", "title": "Payroll", "requestText": "Payroll register for last two pay periods.", "priority": 1, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_005", "title": "Payroll", "requestText": "When was your last rate increase, by how much did you increase, and how often do you raise rates (history for last 3 years)?", "priority": 1, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_006", "title": "REIT", "requestText": "Please complete tab 8.", "priority": 1, "requestType": "document", "subCategory": "REIT", "defaultOwnerRole": "seller"}, {"key": "marina_dd_007", "title": "Rent Rolls", "requestText": "Trailing twelve months and last 2-3 year-end rent rolls, broken out by month, for boat storage and commercial tenants.", "priority": 1, "requestType": "document", "subCategory": "Rent Rolls", "defaultOwnerRole": "seller"}, {"key": "marina_dd_008", "title": "Trial Balances", "requestText": "Trial Balance for last 2-3 years in excel, QuickBooks or similar.", "priority": 1, "requestType": "document", "subCategory": "Trial Balances", "defaultOwnerRole": "seller"}, {"key": "marina_dd_009", "title": "Accounts Receivable", "requestText": "Accounts receivable aging and delinquency reports and accounts payable aging reports for the twelve(12) months immediately preceding the effective date", "priority": 2, "requestType": "document", "subCategory": "Accounts Receivable", "defaultOwnerRole": "seller"}, {"key": "marina_dd_010", "title": "Bank", "requestText": "Copies of the monthly bank statements, Bank Records, cash receipts journals, and bank reconciliation for the twenty-four (24) months immediately preceding the effective date", "priority": 2, "requestType": "document", "subCategory": "Bank", "defaultOwnerRole": "seller"}, {"key": "marina_dd_011", "title": "CapEx Budget", "requestText": "The monthly capital expenditure budget for the twenty-four (24) months immediately preceding the effective date", "priority": 2, "requestType": "document", "subCategory": "CapEx Budget", "defaultOwnerRole": "seller"}, {"key": "marina_dd_012", "title": "CapEx Spend", "requestText": "Have there been any big Capital projects in the last two years and what are costs associated with these projects? Example new 100K spent on installing new docks, new RV sites, buildings etc....", "priority": 2, "requestType": "document", "subCategory": "CapEx Spend", "defaultOwnerRole": "seller"}, {"key": "marina_dd_013", "title": "Income Tax-Federal", "requestText": "Asset & Depreciation Report", "priority": 2, "requestType": "document", "subCategory": "Income Tax-Federal", "defaultOwnerRole": "seller"}, {"key": "marina_dd_014", "title": "Income Tax-Federal", "requestText": "Sellers'' filed income tax returns relating to each property for the current and prior two (2) tax years, or, if the applicable property has been owned by a seller for less than two (2) tax years, for the period of ownership", "priority": 2, "requestType": "document", "subCategory": "Income Tax-Federal", "defaultOwnerRole": "seller"}, {"key": "marina_dd_015", "title": "Income Tax-State", "requestText": "Sellers'' filed state sales tax returns relating to each property for the current and prior two (2) tax years, or, if the applicable property has been owned by a seller for less than two (2) tax years, for the period of ownership", "priority": 2, "requestType": "document", "subCategory": "Income Tax-State", "defaultOwnerRole": "seller"}, {"key": "marina_dd_016", "title": "Inventory", "requestText": "Inventory on hand for ship store, service department, parts, restaurant, fuel, etc.", "priority": 2, "requestType": "document", "subCategory": "Inventory", "defaultOwnerRole": "seller"}, {"key": "marina_dd_017", "title": "Pedestal", "requestText": "Please populate Pedestal tab if applicable", "priority": 2, "requestType": "document", "subCategory": "Pedestal", "defaultOwnerRole": "seller"}, {"key": "marina_dd_018", "title": "Personal Property", "requestText": "Please complete tab 7.", "priority": 2, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}, {"key": "marina_dd_019", "title": "Personal Property", "requestText": "Sellers'' personal property tax bills and renditions relating to each property for the current and prior two (2) tax years or, if the applicable property has been owned by a seller for less than two (2) tax years, for the period of ownership", "priority": 2, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}, {"key": "marina_dd_020", "title": "Property Tax", "requestText": "Property''s real estate tax bills and assessments for the current and prior two (2) tax years or, if the applicable property has been owned by a seller for less than two (2) tax years, for the period of ownership", "priority": 2, "requestType": "document", "subCategory": "Property Tax", "defaultOwnerRole": "seller"}, {"key": "marina_dd_021", "title": "Security Deposits", "requestText": "Security Deposit Policy - what are the policies (e.g. one month rent) & fare discounts given to customers", "priority": 2, "requestType": "document", "subCategory": "Security Deposits", "defaultOwnerRole": "seller"}, {"key": "marina_dd_022", "title": "Utilities", "requestText": "Please complete tab 6.", "priority": 2, "requestType": "document", "subCategory": "Utilities", "defaultOwnerRole": "seller"}, {"key": "marina_dd_023", "title": "Utilities", "requestText": "Utility bills for the twelve (12) months immediately preceding the effective date. (e.g.. electric, water, sewer, gas, trash, waste, phone, cable, internet, etc.)", "priority": 2, "requestType": "document", "subCategory": "Utilities", "defaultOwnerRole": "seller"}, {"key": "marina_dd_024", "title": "Banking", "requestText": "List of Recurring Charges & Automatic Debits", "priority": 3, "requestType": "document", "subCategory": "Banking", "defaultOwnerRole": "seller"}, {"key": "marina_dd_025", "title": "Check Registers", "requestText": "Check Registers for the prior twelve months", "priority": 3, "requestType": "document", "subCategory": "Check Registers", "defaultOwnerRole": "seller"}, {"key": "marina_dd_026", "title": "Credit Cards", "requestText": "List of credit card holders at each property & credit limit for each card holder", "priority": 3, "requestType": "document", "subCategory": "Credit Cards", "defaultOwnerRole": "seller"}, {"key": "marina_dd_027", "title": "Customer ACH info", "requestText": "List of customers paying by direct debit, and subsequent bank account information", "priority": 3, "requestType": "document", "subCategory": "Customer ACH info", "defaultOwnerRole": "seller"}, {"key": "marina_dd_028", "title": "Payments", "requestText": "Please list all accepted payment types (i.e. cash, credit card, check, ACH)", "priority": 3, "requestType": "document", "subCategory": "Payments", "defaultOwnerRole": "seller"}, {"key": "marina_dd_029", "title": "Security Deposits", "requestText": "A schedule/summary of customers with security deposits on file and third party tenants", "priority": 3, "requestType": "document", "subCategory": "Security Deposits", "defaultOwnerRole": "seller"}, {"key": "supp_leases", "title": "Lease Summary", "requestText": "Please complete the Summary of Leases tab for all third-party tenants and lease obligations including term, rent amount, security deposits, annual increases, renewal options, and tenant responsibilities. This includes both income-producing leases (office space, boat club, restaurant) and expense leases (submerged land lease, equipment leases).", "priority": 1, "requestType": "document", "subCategory": "Leases", "defaultOwnerRole": "seller"}, {"key": "supp_utilities", "title": "Utility Summary", "requestText": "Please complete the Utility Summary tab listing all property utilities including provider name, service type, account number, and contact information for account transfers.", "priority": 2, "requestType": "document", "subCategory": "Utilities", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'HR & Payroll DD Requests', 'HR & Payroll - 12 items', 'custom', 'Marina', '[]'::jsonb, true, true, 3, 'general_cre', true, '{"name": "HR & Payroll", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "hr_and_payroll", "title": "HR & Payroll", "items": [{"key": "marina_dd_030", "title": "Org Chart", "requestText": "Property org chart.", "priority": 1, "requestType": "document", "subCategory": "Org Chart", "defaultOwnerRole": "seller"}, {"key": "marina_dd_031", "title": "Payroll", "requestText": "Employee roster: Please include names, titles, departments, special skills, pay rates, job descriptions, length of employment, approximate number of hours worked per week, number of weeks worked per year, amount of paid time off and vacation time provided, and the remaining paid time off and vacation day balance for each employee for the current year.", "priority": 1, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_032", "title": "Payroll", "requestText": "Payroll payment schedule (i.e. weekly, bi-weekly, monthly)", "priority": 1, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_033", "title": "Benefits", "requestText": "Current employee benefits (e.g.. health, dental, vision, supplemental, 401k) and carrier for each benefit plan along with list of premiums paid by employer and employee", "priority": 2, "requestType": "document", "subCategory": "Benefits", "defaultOwnerRole": "seller"}, {"key": "marina_dd_034", "title": "Bonus", "requestText": "Detailed list of bonuses offered & historical records from past 2 years", "priority": 3, "requestType": "document", "subCategory": "Bonus", "defaultOwnerRole": "seller"}, {"key": "marina_dd_035", "title": "Cobra", "requestText": "TPA (third party administrators) agreements for COBRA benefit administration and/ or worker''s comp claims", "priority": 3, "requestType": "document", "subCategory": "Cobra", "defaultOwnerRole": "seller"}, {"key": "marina_dd_036", "title": "Employment Agreements", "requestText": "Employment agreements, contracts, consulting agreements, non-compete agreements.", "priority": 3, "requestType": "document", "subCategory": "Employment Agreements", "defaultOwnerRole": "seller"}, {"key": "marina_dd_037", "title": "Handbook", "requestText": "Employee handbook, if applicable", "priority": 3, "requestType": "document", "subCategory": "Handbook", "defaultOwnerRole": "seller"}, {"key": "marina_dd_038", "title": "Medical Claims", "requestText": "List last two years of medical claims data", "priority": 3, "requestType": "document", "subCategory": "Medical Claims", "defaultOwnerRole": "seller"}, {"key": "marina_dd_039", "title": "OSHA", "requestText": "OSHA 300 Reports 300, 300A and 301 for past 3 years.", "priority": 3, "requestType": "document", "subCategory": "OSHA", "defaultOwnerRole": "seller"}, {"key": "marina_dd_040", "title": "Payroll", "requestText": "List of individuals working and not compensated through payroll", "priority": 3, "requestType": "document", "subCategory": "Payroll", "defaultOwnerRole": "seller"}, {"key": "marina_dd_041", "title": "Whistleblower", "requestText": "List any whistleblower or wrongful termination matters.", "priority": 3, "requestType": "document", "subCategory": "Whistleblower", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Legal DD Requests', 'Legal - 5 items', 'custom', 'Marina', '[]'::jsonb, true, true, 4, 'general_cre', true, '{"name": "Legal", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "legal", "title": "Legal", "items": [{"key": "marina_dd_042", "title": "HOA Documents", "requestText": "HOA/POA documents, if applicable.", "priority": 1, "requestType": "document", "subCategory": "HOA Documents", "defaultOwnerRole": "seller"}, {"key": "marina_dd_043", "title": "HOA Requirements", "requestText": "Written explanation of the monthly/annual responsibilities/requirements to the HOA/POA, if applicable", "priority": 1, "requestType": "document", "subCategory": "HOA Requirements", "defaultOwnerRole": "seller"}, {"key": "marina_dd_044", "title": "Boat/Vehicle Titles", "requestText": "Marina-owned boat & vehicle titles", "priority": 2, "requestType": "document", "subCategory": "Boat/Vehicle Titles", "defaultOwnerRole": "seller"}, {"key": "marina_dd_045", "title": "Title", "requestText": "Title to property", "priority": 2, "requestType": "document", "subCategory": "Title", "defaultOwnerRole": "seller"}, {"key": "supp_permits", "title": "Permits & Licenses Summary", "requestText": "Please complete the Summary of Permits tab listing all permits and licenses including type, purpose, term, expiry date, and department contact information.", "priority": 1, "requestType": "document", "subCategory": "Permits", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Operations DD Requests', 'Operations - 20 items', 'custom', 'Marina', '[]'::jsonb, true, true, 5, 'general_cre', true, '{"name": "Operations", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "operations", "title": "Operations", "items": [{"key": "marina_dd_046", "title": "Rate Card", "requestText": "Current rate card, as well as historical rates over the last 3-5 years.", "priority": 1, "requestType": "document", "subCategory": "Rate Card", "defaultOwnerRole": "seller"}, {"key": "marina_dd_047", "title": "Dredging", "requestText": "Please summarize the history of dredging at the property, as well as how often you dredge, and what that work typically costs.", "priority": 1, "requestType": "document", "subCategory": "Dredging", "defaultOwnerRole": "seller"}, {"key": "marina_dd_048", "title": "Do you allow customers to rent theirs boats or RVs through A", "requestText": "Do you allow customers to rent theirs boats or RVs through Airbnb/VBRO, or other third-party?", "priority": 1, "requestType": "document", "subCategory": null, "defaultOwnerRole": "seller"}, {"key": "marina_dd_049", "title": "Leases", "requestText": "Template boat storage, RV park, and other rental contracts (e.g. boat rentals, cabin rentals, etc.)", "priority": 2, "requestType": "document", "subCategory": "Leases", "defaultOwnerRole": "seller"}, {"key": "marina_dd_050", "title": "Leases", "requestText": "Please provide PDF Copies of all leases in-place with vendors, as well as upland and/or submerged land leases. Additionally, please summarize on tab 3 all the applicable leases for the property. These can include leases with tenants that pay the property, as well as leases where property pays as a lessee (e.g. submerged land or ground lease, equipment lease). Please include name of the vendor, monthly rent, lease term and expiry date.", "priority": 2, "requestType": "document", "subCategory": "Leases", "defaultOwnerRole": "seller"}, {"key": "marina_dd_051", "title": "Permits/Licenses", "requestText": "Please provide copies of all business licenses, sales and use tax licenses, liquor license, retail license, UST/AST permit, storm water permit, hazardous material permit, and any other operating permits and licenses required for operation", "priority": 2, "requestType": "document", "subCategory": "Permits/Licenses", "defaultOwnerRole": "seller"}, {"key": "marina_dd_052", "title": "Permits/Licenses", "requestText": "Pleas complete tab 4.", "priority": 2, "requestType": "document", "subCategory": "Permits/Licenses", "defaultOwnerRole": "seller"}, {"key": "marina_dd_053", "title": "Registered Vehicles/Vessels Etc.", "requestText": "Please complete tab 5.", "priority": 2, "requestType": "document", "subCategory": "Registered Vehicles/Vessels Etc.", "defaultOwnerRole": "seller"}, {"key": "marina_dd_054", "title": "Service Contracts", "requestText": "PDF Copies of all service agreements/contracts currently in-place, as well as completion of tab 2.", "priority": 2, "requestType": "document", "subCategory": "Service Contracts", "defaultOwnerRole": "seller"}, {"key": "marina_dd_055", "title": "Leases", "requestText": "Please provide copies of customer contracts (boat storage, RV park, long-term rentals, etc.)", "priority": 2, "requestType": "document", "subCategory": "Leases", "defaultOwnerRole": "seller"}, {"key": "marina_dd_056", "title": "Permits/Licenses", "requestText": "Any additional agreements in-place, including marina operating permits, easements, licenses, etc.", "priority": 2, "requestType": "document", "subCategory": "Permits/Licenses", "defaultOwnerRole": "seller"}, {"key": "marina_dd_057", "title": "Electric/Utilities", "requestText": "Please explain the customer billing procedure (and include whether utilities are included).", "priority": 3, "requestType": "document", "subCategory": "Electric/Utilities", "defaultOwnerRole": "seller"}, {"key": "marina_dd_058", "title": "Increases", "requestText": "Please explain your rent increase notice procedure and schedule (i.e. do rates increase on a particular date each year, how do you determine the %/$ increase, etc.)", "priority": 3, "requestType": "document", "subCategory": "Increases", "defaultOwnerRole": "seller"}, {"key": "marina_dd_059", "title": "Late Fees", "requestText": "Is there a late fees policy?", "priority": 3, "requestType": "document", "subCategory": "Late Fees", "defaultOwnerRole": "seller"}, {"key": "marina_dd_060", "title": "Memberships/Discounts", "requestText": "Details of membership programs and discounts offered and any documents that support this where applicable (i.e. if not in the Storage / Slip Agreement)", "priority": 3, "requestType": "document", "subCategory": "Memberships/Discounts", "defaultOwnerRole": "seller"}, {"key": "marina_dd_061", "title": "Wait List", "requestText": "Waiting lists for storage and slip and hurricane storage, if applicable", "priority": 3, "requestType": "document", "subCategory": "Wait List", "defaultOwnerRole": "seller"}, {"key": "supp_service_agreements", "title": "Service Agreements Summary", "requestText": "Please complete the Service Agreements tab listing all vendor contracts including terms, fees, expiry dates, and termination notice requirements.", "priority": 1, "requestType": "document", "subCategory": "Service Agreements", "defaultOwnerRole": "seller"}, {"key": "supp_boats_vehicles", "title": "Marina-Owned Vehicles & Equipment", "requestText": "Please complete the Boats & Vehicle Info tab listing all marina-owned vehicles and equipment including type, model, serial number, registration, use, year, engine details, purchase date, and condition.", "priority": 1, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}, {"key": "supp_personal_property", "title": "Personal Property Inventory", "requestText": "Please complete the Personal Property Template tab listing all personal property items including description, age, location, and current market value.", "priority": 2, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}, {"key": "supp_pedestal", "title": "Pedestal Information", "requestText": "Please complete the Pedestal Information tab listing pedestal count, model numbers, power type, and photos.", "priority": 2, "requestType": "document", "subCategory": "Pedestals", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Real Estate DD Requests', 'Real Estate - 11 items', 'custom', 'Marina', '[]'::jsonb, true, true, 6, 'general_cre', true, '{"name": "Real Estate", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "real_estate", "title": "Real Estate", "items": [{"key": "marina_dd_062", "title": "Appraisals", "requestText": "Past appraisal(s) of the property", "priority": 1, "requestType": "document", "subCategory": "Appraisals", "defaultOwnerRole": "seller"}, {"key": "marina_dd_063", "title": "Environmental", "requestText": "Previous environmental Phase I and/or Phase II, if available", "priority": 1, "requestType": "document", "subCategory": "Environmental", "defaultOwnerRole": "seller"}, {"key": "marina_dd_064", "title": "Property Condition", "requestText": "Past property condition reports, if available", "priority": 1, "requestType": "document", "subCategory": "Property Condition", "defaultOwnerRole": "seller"}, {"key": "marina_dd_065", "title": "Real Property", "requestText": "Please provide confirmation of parcels or legal descriptions to show what parcels of land are included in the sale", "priority": 1, "requestType": "document", "subCategory": "Real Property", "defaultOwnerRole": "seller"}, {"key": "marina_dd_066", "title": "Site Plan", "requestText": "Marina site plan and dock layout for each of the properties", "priority": 1, "requestType": "document", "subCategory": "Site Plan", "defaultOwnerRole": "seller"}, {"key": "marina_dd_067", "title": "Surveys", "requestText": "Surveys of the properties (e.g. ALTA, bathymetric, etc.)", "priority": 1, "requestType": "document", "subCategory": "Surveys", "defaultOwnerRole": "seller"}, {"key": "marina_dd_068", "title": "Water Rights", "requestText": "Documents establishing water rights.", "priority": 1, "requestType": "document", "subCategory": "Water Rights", "defaultOwnerRole": "seller"}, {"key": "marina_dd_069", "title": "Zoning", "requestText": "Zoning Letter from local municipality or any documentation showing property zoning.", "priority": 1, "requestType": "document", "subCategory": "Zoning", "defaultOwnerRole": "seller"}, {"key": "marina_dd_070", "title": "Insurance", "requestText": "Elevation Certificates (required by Flood insurance)", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_071", "title": "Real Estate", "requestText": "All master plans for the properties, if available", "priority": 2, "requestType": "document", "subCategory": "Real Estate", "defaultOwnerRole": "seller"}, {"key": "supp_boats_vehicles", "title": "Marina-Owned Vehicles & Equipment", "requestText": "Please complete the Boats & Vehicle Info tab listing all marina-owned vehicles and equipment including type, model, serial number, registration, use, year, engine details, purchase date, and condition.", "priority": 1, "requestType": "document", "subCategory": "Personal Property", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Information Technology DD Requests', 'Information Technology - 1 items', 'custom', 'Marina', '[]'::jsonb, true, true, 7, 'general_cre', true, '{"name": "Information Technology", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "information_technology", "title": "Information Technology", "items": [{"key": "marina_dd_072", "title": "IT", "requestText": "Please complete tab 10", "priority": 2, "requestType": "document", "subCategory": "IT", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Inspections DD Requests', 'Inspections - 6 items', 'custom', 'Marina', '[]'::jsonb, true, true, 8, 'general_cre', true, '{"name": "Inspections", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "inspections", "title": "Inspections", "items": [{"key": "marina_dd_073", "title": "Inspections", "requestText": "Certificates of occupancy and zoning reports", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_074", "title": "Inspections", "requestText": "Fire Inspection / Equipment testing", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_075", "title": "Inspections", "requestText": "Recent Electrical Inspection", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_076", "title": "Inspections", "requestText": "Recent Forklift Inspection", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_077", "title": "Inspections", "requestText": "Underground Storage Tank Inspection", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}, {"key": "marina_dd_078", "title": "Inspections", "requestText": "Weights and Measures Inspection (Fuel Pumps), if available", "priority": 2, "requestType": "document", "subCategory": "Inspections", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Insurance DD Requests', 'Insurance - 10 items', 'custom', 'Marina', '[]'::jsonb, true, true, 9, 'general_cre', true, '{"name": "Insurance", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "insurance", "title": "Insurance", "items": [{"key": "marina_dd_079", "title": "Insurance", "requestText": "A detailed description of any outstanding workers'' compensation claims relating to the properties for the twenty-four (24) months immediately preceding the effective date.", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_080", "title": "Insurance", "requestText": "Flood insurance policies", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_081", "title": "Insurance", "requestText": "Insurance loss run for preceding 5 years", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_082", "title": "Insurance", "requestText": "Insurance policies", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_083", "title": "Insurance", "requestText": "Pending or threatened claims for the preceding 36 months", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_084", "title": "Insurance", "requestText": "Storage tank insurance", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_085", "title": "Insurance", "requestText": "Title insurance", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_086", "title": "Insurance", "requestText": "Copy of workers'' comp policy", "priority": 2, "requestType": "document", "subCategory": "Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_087", "title": "Customer Proof Of Insurance", "requestText": "Does the Marina ask their customers to name the marina as additionally insured on their vessels insurance?", "priority": 2, "requestType": "document", "subCategory": "Customer Proof Of Insurance", "defaultOwnerRole": "seller"}, {"key": "marina_dd_088", "title": "Customer Proof Of Insurance", "requestText": "Does the marina request copies of boat storage customer insurance?", "priority": 2, "requestType": "document", "subCategory": "Customer Proof Of Insurance", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Marketing DD Requests', 'Marketing - 3 items', 'custom', 'Marina', '[]'::jsonb, true, true, 10, 'general_cre', true, '{"name": "Marketing", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "marketing", "title": "Marketing", "items": [{"key": "marina_dd_089", "title": "Advertising", "requestText": "Marketing plans, advertising agreements, brochures, welcome packages. Any commitments to boat shows, radio, newspaper, magazines, social media etc.", "priority": 3, "requestType": "document", "subCategory": "Advertising", "defaultOwnerRole": "seller"}, {"key": "marina_dd_090", "title": "Email Customer List", "requestText": "Customer lists with emails", "priority": 3, "requestType": "document", "subCategory": "Email Customer List", "defaultOwnerRole": "seller"}, {"key": "marina_dd_091", "title": "Marketing", "requestText": "Marina''s logo and high res photo''s.", "priority": 3, "requestType": "document", "subCategory": "Marketing", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'Vendors DD Requests', 'Vendors - 2 items', 'custom', 'Marina', '[]'::jsonb, true, true, 11, 'general_cre', true, '{"name": "Vendors", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "vendors", "title": "Vendors", "items": [{"key": "marina_dd_092", "title": "AP Vendors", "requestText": "List of vendors that work with the property (i.e. pest, fuel, security, landscaping, cleaning, machinery, ice, uniform, fire inspections, maintenance, etc.)", "priority": 3, "requestType": "document", "subCategory": "AP Vendors", "defaultOwnerRole": "seller"}, {"key": "marina_dd_093", "title": "W9''s", "requestText": "Copies of W9 and Tax ID for each vendor", "priority": 3, "requestType": "document", "subCategory": "W9''s", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'REIT Compliance DD Requests', 'REIT Compliance - 22 items', 'custom', 'Marina', '[]'::jsonb, true, true, 12, 'general_cre', true, '{"name": "REIT Compliance", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "reit_compliance", "title": "REIT Compliance", "items": [{"key": "reit_001", "title": "Do you expect the value of personal property (e.g., furniture, equipment, applia", "requestText": "Do you expect the value of personal property (e.g., furniture, equipment, appliances, light fixtures) of the Property being acquired, including expected future additions, to represent 15% or more of the total purchase price of the Property?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_002", "title": "If yes, is any of this personal property leased to tenants in connection with th", "requestText": "If yes, is any of this personal property leased to tenants in connection with the leased Property?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_003", "title": "If yes, what is the fair market value of such personal property?", "requestText": "If yes, what is the fair market value of such personal property?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_004", "title": "What''s the minimum rental period for a standard lease?", "requestText": "What''s the minimum rental period for a standard lease?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_005", "title": "Do any leases provide for rent based in whole or in part on the net income or ne", "requestText": "Do any leases provide for rent based in whole or in part on the net income or net profits of the tenant?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_006", "title": "Do any leases that provide for rent based in whole or in part on a fixed percent", "requestText": "Do any leases that provide for rent based in whole or in part on a fixed percentage of gross receipts or sales also provide for a reduction of such gross receipts or sales by the amount of any tenant expense in a manner that results in rent in substance being based on net income or profits?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_007", "title": "Are there any leases with tenants that permit subleasing, where the terms of the", "requestText": "Are there any leases with tenants that permit subleasing, where the terms of the lease or sublease provide for rent based on terms similar to the terms above?  (These terms of the sublease can taint the terms of the lease.)", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_008", "title": "If yes, are there any subleases currently in place?  If yes, please list subleas", "requestText": "If yes, are there any subleases currently in place?  If yes, please list subleases:", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_009", "title": "Does the property or its investors own directly or indirectly a 10% interest in ", "requestText": "Does the property or its investors own directly or indirectly a 10% interest in any tenant?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_010", "title": "Is the property reimbursed by tenants for any items other than the following: (a", "requestText": "Is the property reimbursed by tenants for any items other than the following: (a) real estate taxes; (b) insurance premiums; (c) maintenance charges; (d) utilities; (e) expense of an independent audit of the tenant\u2019s books to determine the tenant\u2019s gross sales (on which to base percentage rent); (f) attorney fees incurred as a result of a default on the lease; (g) expenses for marketing the Property; or (h) similar items?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_011", "title": "In addition to rent and the reimbursements listed above, do any leases require t", "requestText": "In addition to rent and the reimbursements listed above, do any leases require the tenant to pay any additional amounts other than the following: (a) rent increases based upon an objective cost-of-living index; (b) late payment charges; (c) forfeited security deposits; or (d) lease termination payments?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_012", "title": "Did the books and records, including budgets, of the seller indicate the owner r", "requestText": "Did the books and records, including budgets, of the seller indicate the owner receives any amounts other than rent, reimbursements and escalations?  For example, is there an amount listed as \u201cOther Income\u201d?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_013", "title": "If yes, what is the nature of the other income?  Please list all sources.", "requestText": "If yes, what is the nature of the other income?  Please list all sources.", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "owner_admin"}, {"key": "reit_014", "title": "What is the anticipated useful life of the floating docks?", "requestText": "What is the anticipated useful life of the floating docks?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_015", "title": "Is the method used to affix the docks designed and built with a configuration in", "requestText": "Is the method used to affix the docks designed and built with a configuration in mind which is not intended to be moved or destroyed?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_016", "title": "Is the method used affixed to the seabed meant to be permanent (i.e., not easily", "requestText": "Is the method used affixed to the seabed meant to be permanent (i.e., not easily destroyed)?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_017", "title": "Is the method used meant to be resistant to inclement weather (e.g., hurricanes)", "requestText": "Is the method used meant to be resistant to inclement weather (e.g., hurricanes)?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_018", "title": "If the method used needed to be reconfigured or moved, would this cause the pili", "requestText": "If the method used needed to be reconfigured or moved, would this cause the pilings and/or the floating dock to be damaged or destroyed?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_019", "title": "How long would it take to remove the method used from the seabed?", "requestText": "How long would it take to remove the method used from the seabed?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_020", "title": "Is it monetarily prohibitive to make changes, alter, or move the method used to ", "requestText": "Is it monetarily prohibitive to make changes, alter, or move the method used to connect the floating docks to the sea bottom?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_021", "title": "If the marina ceased to operate, does the local municipality require removal or ", "requestText": "If the marina ceased to operate, does the local municipality require removal or destruction of the method used?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}, {"key": "reit_022", "title": "Are there any other circumstances that would indicate or suggest the expected pe", "requestText": "Are there any other circumstances that would indicate or suggest the expected period of affixation to the seabed is not indefinite?", "priority": 2, "requestType": "data", "subCategory": "REIT Compliance", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
INSERT INTO dd_checklist_templates (id, name, description, template_type, category, tasks, is_system, is_active, sort_order, asset_class, is_builtin, data, version) VALUES (gen_random_uuid(), 'IT Infrastructure DD Requests', 'IT Infrastructure - 17 items', 'custom', 'Marina', '[]'::jsonb, true, true, 13, 'general_cre', true, '{"name": "IT Infrastructure", "version": "2.0.0", "assetClass": "general_cre", "sections": [{"key": "it_infrastructure", "title": "IT Infrastructure", "items": [{"key": "it_001", "title": "Is the IT Equipment Part of the Sale (Yes/No)? (I.e. PCs and Related Equipment, ", "requestText": "Is the IT Equipment Part of the Sale (Yes/No)? (I.e. PCs and Related Equipment, Copiers, Scanners)", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_002", "title": "Describe Your Internet Service Type (i.e. Cable, DSL, Fiber, T1, Satellite/Cellu", "requestText": "Describe Your Internet Service Type (i.e. Cable, DSL, Fiber, T1, Satellite/Cellular)?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_003", "title": "What is the Speed of Your Internet Service?", "requestText": "What is the Speed of Your Internet Service?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_004", "title": "Is your IP Addressing Automatic or Static?", "requestText": "Is your IP Addressing Automatic or Static? If Static, please provide details: IP address, Subnet Mask, Gateway Address, DNS1, and DNS2", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_005", "title": "Who is your Internet Service Provider and their contact information?", "requestText": "Who is your Internet Service Provider and their contact information?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_006", "title": "Who is Authorized to Make Changes on your Office Internet Account?", "requestText": "Who is Authorized to Make Changes on your Office Internet Account?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_007", "title": "Please fill out the information below: (If all your computers are housed inside ", "requestText": "Please fill out the information below: (If all your computers are housed inside 1 building, the fill out the information for Building 1)", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_008", "title": "Do You Provide WiFi Service to Residents/Guests?", "requestText": "Do You Provide WiFi Service to Residents/Guests? If Yes, is the service in the form of Hotspot(s) or Park-wide? Who manages the service?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_009", "title": "Do You Provide Walk-Up Computer Access to Residents/Guests?", "requestText": "Do You Provide Walk-Up Computer Access to Residents/Guests?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_010", "title": "Is there a Firewall connected to your Office Internet Service (Yes/No)?", "requestText": "Is there a Firewall connected to your Office Internet Service (Yes/No)?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_011", "title": "Are there any Servers Connected to the Network?", "requestText": "Are there any Servers Connected to the Network? If Yes, please include details: Function, Make and Model Number, Serial Number.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_012", "title": "Are Your Computers Connected to the Network via a Cable or are they Wireless?", "requestText": "Are Your Computers Connected to the Network via a Cable or are they Wireless?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_013", "title": "Are There any E-mail Addresses that need to be transferred or Redirected? If yes", "requestText": "Are There any E-mail Addresses that need to be transferred or Redirected? If yes, please list all users email addresses below.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_014", "title": "Does Your Property Have a Website (Yes/No)?", "requestText": "Does Your Property Have a Website (Yes/No)? IMPORTANT: please provide Site Address, Site Administrator Name, Hosting Company and Contact Info, and the Email Address listed at the Registrar.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_015", "title": "Do you have any Leased Equipment (i.e Copier, Stamp Machine)? If yes, please pro", "requestText": "Do you have any Leased Equipment (i.e Copier, Stamp Machine)? If yes, please provide the companies name and contact information.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_016", "title": "What property Management Software do you use and can you provide us with their c", "requestText": "What property Management Software do you use and can you provide us with their contact information?", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}, {"key": "it_017", "title": "Is Your Property Management Software Hosted? If yes, please provide contact info", "requestText": "Is Your Property Management Software Hosted? If yes, please provide contact information for hosting service or sales contact.", "priority": 2, "requestType": "data", "subCategory": "IT Infrastructure", "defaultOwnerRole": "seller"}]}]}'::jsonb, '2.0.0');
